// ── Main calendar ───────────────────────────────────────────────────────────

export default function WeeklyCalendar({
  sessions,
  priorities,
  weekOffset,
  onChangeWeek,
  onSelectSession,
  onSelectPriority,
  onSessionMoved,
}: Props) {
  const [activeSession, setActiveSession] = useState<SessionWithBook | null>(null)
  const [optimisticMoves, setOptimisticMoves] = useState<Record<string, string>>({})

  const todayStart = startOfDay(new Date())
  const weekStart = addWeeks(startOfWeek(new Date(), { weekStartsOn: 1 }), weekOffset)
  const days = Array.from({ length: 7 }, (_, i) => addDays(weekStart, i))
  const weekLabel = `${format(days[0], 'MMM d')} – ${format(days[6], 'MMM d, yyyy')}`

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 6 } }))

  // Apply optimistic moves so the UI updates before the network round-trip
  const displaySessions = sessions.map(s =>
    optimisticMoves[s.id] ? { ...s, scheduled_date: optimisticMoves[s.id] } : s
  )

  function handleDragStart(event: DragStartEvent) {
    const s = sessions.find(s => s.id === event.active.id)
    setActiveSession(s ?? null)
  }

  async function handleDragEnd(event: DragEndEvent) {
    setActiveSession(null)
    const { active, over } = event
    if (!over) return

    const sessionId = active.id as string
    const newDate = over.id as string
    const session = sessions.find(s => s.id === sessionId)
    if (!session || session.scheduled_date === newDate) return

    // Optimistic update
    setOptimisticMoves(prev => ({ ...prev, [sessionId]: newDate }))

    await fetch(`/api/sessions/${sessionId}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ scheduled_date: newDate }),
    })

    setOptimisticMoves(prev => {
      const next = { ...prev }
      delete next[sessionId]
      return next
    })
    onSessionMoved()
  }

  return (
    <DndContext
      sensors={sensors}
      onDragStart={handleDragStart}
      onDragEnd={handleDragEnd}
    >
      {/* Week navigation */}
      <div className="flex items-center justify-between mb-4">
        <button
          onClick={() => onChangeWeek(weekOffset - 1)}
          className="text-sm text-stone-500 hover:text-stone-800 px-3 py-1.5 rounded-lg hover:bg-stone-100 transition-colors"
        >
          ← Prev
        </button>
        <span className="text-sm font-medium text-stone-600">{weekLabel}</span>
        <button
          onClick={() => onChangeWeek(weekOffset + 1)}
          className="text-sm text-stone-500 hover:text-stone-800 px-3 py-1.5 rounded-lg hover:bg-stone-100 transition-colors"
        >
          Next →
        </button>
      </div>

      {/* Calendar grid */}
      <div className="overflow-x-auto">
        <div className="grid grid-cols-7 min-w-[560px] rounded-xl border border-stone-200 overflow-hidden bg-stone-50">
          {days.map((day, i) => {
            const iso = format(day, 'yyyy-MM-dd')
            const isCurrentDay = isToday(day)
            const isPast = isBefore(day, todayStart)
            const daySessions = displaySessions.filter(s => s.scheduled_date === iso)
            const dayItems = priorities.filter(p => p.scheduled_date === iso)

            const completedSessions = daySessions.filter(s => s.is_completed)
            const upcomingSessions = daySessions.filter(s => !s.is_completed)

            return (
              <div
                key={iso}
                className={`flex flex-col relative ${i < 6 ? 'border-r border-stone-100' : ''} ${
                  isCurrentDay ? 'bg-blue-50/50' : ''
                }`}
              >
                {/* Day header */}
                <div className={`px-2.5 pt-3 pb-2 border-b border-stone-100 ${
                  isCurrentDay ? 'bg-blue-100/40' : ''
                }`}>
                  <p className={`text-[11px] font-bold tracking-wider uppercase ${
                    isCurrentDay ? 'text-blue-500' : isPast ? 'text-stone-300' : 'text-stone-400'
                  }`}>
                    {DAYS[i]}
                  </p>
                  <p className={`text-2xl font-semibold leading-tight mt-0.5 ${
                    isCurrentDay ? 'text-blue-600' : isPast ? 'text-stone-300' : 'text-stone-600'
                  }`}>
                    {format(day, 'd')}
                  </p>
                </div>

                <DroppableDay date={iso} isCurrentDay={isCurrentDay}>
                  {/* Completed sessions */}
                  {completedSessions.map(session => (
                    <button
                      key={session.id}
                      onClick={() => onSelectSession(session)}
                      className="w-full text-left rounded-md border-l-[3px] border-stone-200 bg-stone-100 px-2 py-1.5 text-xs shadow-sm transition-all opacity-50"
                    >
                      <p className="font-semibold truncate leading-tight text-stone-400 line-through">
                        {session.book.title}
                      </p>
                      <p className="mt-0.5 text-stone-300 flex items-center gap-1">
                        <span>✓</span>
                        <span>pp.&nbsp;{session.pages_start}–{session.actual_end_page ?? session.pages_end}</span>
                      </p>
                    </button>
                  ))}

                  {/* Upcoming sessions — draggable */}
                  {upcomingSessions.map(session => (
                    <DraggableSession
                      key={session.id}
                      session={session}
                      onClick={() => onSelectSession(session)}
                    />
                  ))}

                  {/* Priority items */}
                  {dayItems.map(item => (
                    <button
                      key={item.id}
                      onClick={() => onSelectPriority(item)}
                      className="w-full text-left rounded-md border-l-[3px] border-orange-400 bg-stone-50 hover:bg-orange-50 px-2 py-1.5 text-xs shadow-sm hover:shadow transition-all group"
                    >
                      <p className="font-semibold text-stone-700 truncate group-hover:text-orange-700 transition-colors leading-tight">
                        {item.title}
                      </p>
                      <p className="text-orange-500 mt-0.5">Priority item</p>
                    </button>
                  ))}
                </DroppableDay>
              </div>
            )
          })}
        </div>
      </div>

      <DragOverlay>
        {activeSession && <SessionOverlay session={activeSession} />}
      </DragOverlay>
    </DndContext>
  )
}

'use client'

import { useState } from 'react'
import Modal from './Modal'

interface Props {
  onClose: () => void
  onSuccess: () => void
}

export default function AddBookModal({ onClose, onSuccess }: Props) {
  const [form, setForm] = useState({ title: '', total_pages: '', current_page: '0' })
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setLoading(true)

    const res = await fetch('/api/books', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        title: form.title.trim(),
        total_pages: Number(form.total_pages),
        current_page: Number(form.current_page),
        sessions_per_week: 4,
      }),
    })

    if (!res.ok) {
      const data = await res.json()
      setError(data.error ?? 'Failed to add book')
      setLoading(false)
      return
    }

    onSuccess()
    onClose()
  }

  return (
    <Modal title="Add Book" onClose={onClose}>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-stone-600 mb-1">Title</label>
          <input
            type="text"
            required
            autoFocus
            value={form.title}
            onChange={e => setForm(f => ({ ...f, title: e.target.value }))}
            className="w-full border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            placeholder="Book title"
          />
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="block text-sm font-medium text-stone-600 mb-1">Total pages</label>
            <input
              type="number"
              required
              min={1}
              value={form.total_pages}
              onChange={e => setForm(f => ({ ...f, total_pages: e.target.value }))}
              className="w-full border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="450"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-stone-600 mb-1">Current page</label>
            <input
              type="number"
              min={0}
              value={form.current_page}
              onChange={e => setForm(f => ({ ...f, current_page: e.target.value }))}
              className="w-full border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="0"
            />
          </div>
        </div>

        {error && <p className="text-sm text-red-500">{error}</p>}

        <div className="flex gap-3 pt-1">
          <button
            type="button"
            onClick={onClose}
            className="flex-1 border border-stone-200 text-stone-600 px-4 py-2 rounded-lg text-sm hover:bg-stone-100 transition-colors"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="flex-1 bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {loading ? 'Adding…' : 'Add Book'}
          </button>
        </div>
      </form>
    </Modal>
  )
}

