    <div className="bg-stone-50 rounded-xl border border-stone-300 shadow-lg px-5 py-4 opacity-95">
      <p className="text-sm text-stone-700 leading-relaxed">
        &ldquo;{quote.quote_text}&rdquo;
      </p>
      {quote.page_number != null && (
        <p className="text-xs text-stone-400 mt-1.5">p. {quote.page_number}</p>
      )}
    </div>
  )
}

export default function QuotesWithHeadings({ bookId, headings, quotes, onUpdate }: Props) {
  const [newHeadingName, setNewHeadingName] = useState('')
  const [addingHeading, setAddingHeading] = useState(false)

  const [editingHeadingId, setEditingHeadingId] = useState<string | null>(null)
  const [editingHeadingName, setEditingHeadingName] = useState('')

  const [addQuoteHeadingId, setAddQuoteHeadingId] = useState<string | null>(null)
  const [quoteForm, setQuoteForm] = useState({ text: '', page: '' })
  const [addingQuote, setAddingQuote] = useState(false)

  const [activeQuoteId, setActiveQuoteId] = useState<string | null>(null)

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 8 } }))

  // Unassigned quotes (no heading_id or heading deleted)
  const unassignedQuotes = quotes.filter(q => !q.heading_id || !headings.find(h => h.id === q.heading_id))

  async function handleAddHeading() {
    if (!newHeadingName.trim()) return
    setAddingHeading(true)
    const res = await fetch('/api/quote-headings', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ book_id: bookId, name: newHeadingName.trim() }),
    })
    const data = await res.json()
    onUpdate([...headings, data as QuoteHeading], quotes)
    setNewHeadingName('')
    setAddingHeading(false)
  }

  async function handleRenameHeading(id: string, name: string) {
    await fetch(`/api/quote-headings/${id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name }),
    })
    onUpdate(headings.map(h => h.id === id ? { ...h, name } : h), quotes)
    setEditingHeadingId(null)
  }

  async function handleDeleteHeading(id: string) {
    await fetch(`/api/quote-headings/${id}`, { method: 'DELETE' })
    onUpdate(
      headings.filter(h => h.id !== id),
      quotes.map(q => q.heading_id === id ? { ...q, heading_id: null } : q)
    )
  }

  async function handleAddQuote(headingId: string | null) {
    if (!quoteForm.text.trim()) return
    setAddingQuote(true)

    // Get max sort_order for this heading's quotes
    const existingInSection = quotes.filter(q =>
      headingId ? q.heading_id === headingId : !q.heading_id
    )
    const maxOrder = Math.max(0, ...existingInSection.map(q => q.sort_order ?? 0))

    const { data } = await supabase
      .from('quotes')
      .insert({
        book_id: bookId,
        quote_text: quoteForm.text.trim(),
        page_number: quoteForm.page ? Number(quoteForm.page) : null,
        heading_id: headingId,
        sort_order: maxOrder + 1,
      })
      .select()
      .single()

    if (data) {
      onUpdate(headings, [...quotes, data as Quote])
      setQuoteForm({ text: '', page: '' })
      setAddQuoteHeadingId(null)
    }
    setAddingQuote(false)
  }

  async function handleDeleteQuote(quoteId: string) {
    await fetch(`/api/quotes/${quoteId}`, { method: 'DELETE' })
    onUpdate(headings, quotes.filter(q => q.id !== quoteId))
  }

  function handleDragStart(event: DragStartEvent) {
    setActiveQuoteId(event.active.id as string)
  }

  async function handleDragOver(event: DragOverEvent) {
    const { active, over } = event
    if (!over || active.id === over.id) return

    const draggedQuote = quotes.find(q => q.id === active.id)
    if (!draggedQuote) return

    // Check if 'over' is a heading container
    const overHeading = headings.find(h => h.id === over.id)
    if (overHeading && draggedQuote.heading_id !== overHeading.id) {
      // Moving to a different heading section (hover over heading label)
      const newHeadingId = overHeading.id
      const newQuotes = quotes.map(q =>
        q.id === draggedQuote.id ? { ...q, heading_id: newHeadingId } : q
      )
      onUpdate(headings, newQuotes)
    }
  }

  async function handleDragEnd(event: DragEndEvent) {
    setActiveQuoteId(null)
    const { active, over } = event
    if (!over || active.id === over.id) return

    const draggedQuote = quotes.find(q => q.id === active.id)
    const overQuote = quotes.find(q => q.id === over.id)

    if (!draggedQuote) return

    // Determine target heading
    const overHeading = headings.find(h => h.id === over.id)
    const targetHeadingId = overHeading
      ? overHeading.id
      : overQuote?.heading_id ?? null

    // Get quotes in the target section, sorted
    const sectionQuotes = quotes
      .filter(q => {
        const qHeading = q.heading_id ?? null
        return qHeading === targetHeadingId && q.id !== draggedQuote.id
      })
      .sort((a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0))

    let newOrder: string[]
    if (overQuote) {
      const overIndex = sectionQuotes.findIndex(q => q.id === overQuote.id)
      sectionQuotes.splice(overIndex, 0, draggedQuote)
      newOrder = sectionQuotes.map(q => q.id)
    } else {
      newOrder = [...sectionQuotes.map(q => q.id), draggedQuote.id]
    }

    // Persist new sort_order and heading_id
    const updates = newOrder.map((id, i) => ({
      id,
      sort_order: i + 1,
      heading_id: targetHeadingId,
    }))

    for (const u of updates) {
      await fetch(`/api/quotes/${u.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sort_order: u.sort_order, heading_id: u.heading_id }),
      })
    }

    // Update local state
    const updatedQuotes = quotes.map(q => {
      const upd = updates.find(u => u.id === q.id)
      return upd ? { ...q, sort_order: upd.sort_order, heading_id: upd.heading_id } : q
    })
    onUpdate(headings, updatedQuotes)
  }

  const activeQuote = quotes.find(q => q.id === activeQuoteId)

  function renderAddQuoteForm(headingId: string | null) {
    const isOpen = addQuoteHeadingId === headingId || (headingId === null && addQuoteHeadingId === 'unassigned')
    const openKey = headingId ?? 'unassigned'
    if (!isOpen) {
      return (
        <button
          onClick={() => setAddQuoteHeadingId(openKey)}
          className="text-xs text-stone-400 hover:text-blue-500 transition-colors mt-1"
        >
          + Add quote
        </button>
      )
    }
    return (
      <div className="bg-stone-100 rounded-lg border border-stone-200 p-3 space-y-2 mt-2">
        <textarea
          value={quoteForm.text}
          onChange={e => setQuoteForm(f => ({ ...f, text: e.target.value }))}
          placeholder="Quote text…"
          rows={2}
          autoFocus
          className="w-full resize-none border border-stone-200 rounded-lg px-3 py-2 text-sm text-stone-700 leading-relaxed placeholder:text-stone-300 focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
        />
        <div className="flex gap-2 items-center">
          <label className="text-sm text-stone-500 shrink-0">p.</label>
          <input
            type="number"
            min={1}
            value={quoteForm.page}
            onChange={e => setQuoteForm(f => ({ ...f, page: e.target.value }))}
            placeholder="—"
            className="w-16 border border-stone-200 rounded-lg px-2 py-1.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
          />
          <div className="ml-auto flex gap-2">
            <button
              onClick={() => { setAddQuoteHeadingId(null); setQuoteForm({ text: '', page: '' }) }}
              className="text-sm text-stone-400 hover:text-stone-600 px-3 py-1.5 rounded-lg transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={() => handleAddQuote(headingId)}
              disabled={addingQuote || !quoteForm.text.trim()}
              className="bg-blue-500 hover:bg-blue-600 text-white px-4 py-1.5 rounded-lg text-sm font-medium transition-colors disabled:opacity-40"
            >
              {addingQuote ? 'Adding…' : 'Add'}
            </button>
          </div>
        </div>
      </div>
    )
  }

  const allQuoteIds = quotes.map(q => q.id)

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={closestCenter}
      onDragStart={handleDragStart}
      onDragOver={handleDragOver}
      onDragEnd={handleDragEnd}
    >
      <div className="space-y-6">
        {/* Add new heading */}
        <div className="flex gap-2">
          <input
            value={newHeadingName}
            onChange={e => setNewHeadingName(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') handleAddHeading() }}
            placeholder="New heading name…"
            className="flex-1 border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
          />
          <button
            onClick={handleAddHeading}
            disabled={addingHeading || !newHeadingName.trim()}
            className="bg-stone-700 hover:bg-stone-800 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-40"
          >
            + Heading
          </button>
        </div>

        <SortableContext items={allQuoteIds} strategy={verticalListSortingStrategy}>
          {/* Headings with their quotes */}
          {headings
            .sort((a, b) => a.sort_order - b.sort_order)
            .map(heading => {
              const headingQuotes = quotes
                .filter(q => q.heading_id === heading.id)
                .sort((a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0))

              return (
                <div key={heading.id}>
                  {/* Heading label */}
                  <div className="flex items-center gap-2 mb-2 group/heading">
                    {editingHeadingId === heading.id ? (
                      <div className="flex gap-2 flex-1">
                        <input
                          autoFocus
                          value={editingHeadingName}
                          onChange={e => setEditingHeadingName(e.target.value)}
                          onKeyDown={e => {
                            if (e.key === 'Enter') handleRenameHeading(heading.id, editingHeadingName)
                            if (e.key === 'Escape') setEditingHeadingId(null)
                          }}
                          className="flex-1 text-sm font-semibold border border-stone-300 rounded px-2 py-1 focus:outline-none focus:ring-2 focus:ring-blue-200"
                        />
                        <button
                          onClick={() => handleRenameHeading(heading.id, editingHeadingName)}
                          className="text-xs text-blue-500 hover:text-blue-700"
                        >
                          Save
                        </button>
                        <button
                          onClick={() => setEditingHeadingId(null)}
                          className="text-xs text-stone-400 hover:text-stone-600"
                        >
                          Cancel
                        </button>
                      </div>
                    ) : (
                      <>
                        <h3 className="text-xs font-bold uppercase tracking-widest text-stone-400 flex-1">
                          {heading.name}
                        </h3>
                        <button
                          onClick={() => { setEditingHeadingId(heading.id); setEditingHeadingName(heading.name) }}
                          className="text-xs text-stone-300 hover:text-stone-500 opacity-0 group-hover/heading:opacity-100 transition-opacity"
                        >
                          Rename
                        </button>
                        <button
                          onClick={() => handleDeleteHeading(heading.id)}
                          className="text-xs text-stone-300 hover:text-red-400 opacity-0 group-hover/heading:opacity-100 transition-opacity"
                        >
                          Delete
                        </button>
                      </>
                    )}
                  </div>

                  <div className="space-y-2">
                    {headingQuotes.map(quote => (
                      <SortableQuote
                        key={quote.id}
                        quote={quote}
                        onDelete={handleDeleteQuote}
                      />
                    ))}
                    {headingQuotes.length === 0 && (
                      <p className="text-xs text-stone-300 py-2">Drop quotes here</p>
                    )}
                  </div>
                  {renderAddQuoteForm(heading.id)}
                </div>
              )
            })}

          {/* Unassigned quotes */}
          <div>
            {headings.length > 0 && (
              <h3 className="text-xs font-bold uppercase tracking-widest text-stone-400 mb-2">
                Unsorted
              </h3>
            )}
            <div className="space-y-2">
              {unassignedQuotes
                .sort((a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0))
                .map(quote => (
                  <SortableQuote
                    key={quote.id}
                    quote={quote}
                    onDelete={handleDeleteQuote}
                  />
                ))}
            </div>
            {renderAddQuoteForm(null)}
          </div>
        </SortableContext>
      </div>

      <DragOverlay>
        {activeQuote && <QuoteOverlay quote={activeQuote} />}
      </DragOverlay>
    </DndContext>
  )
}

'use client'

import { useState } from 'react'
import Modal from './Modal'
import type { Session, Book } from '@/types'

interface Props {
  session: Session & { book: Book }
  onClose: () => void
  onSuccess: () => void
}

export default function CompleteSessionModal({ session, onClose, onSuccess }: Props) {
  const [actualPage, setActualPage] = useState(String(session.pages_end))
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setLoading(true)

    const res = await fetch(`/api/sessions/${session.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'complete',
        actual_end_page: Number(actualPage),
      }),
    })

    if (!res.ok) {
      const data = await res.json()
      setError(data.error ?? 'Failed to complete session')
      setLoading(false)
      return
    }

    onSuccess()
    onClose()
  }

  return (
    <Modal title="Complete Session" onClose={onClose}>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="bg-blue-50 rounded-lg px-4 py-3 text-sm">
          <p className="font-medium text-blue-900">{session.book.title}</p>
          <p className="text-blue-600 mt-0.5">
            Planned: pp. {session.pages_start}–{session.pages_end}
          </p>
        </div>

        <div>
          <label className="block text-sm font-medium text-stone-600 mb-1">
            Actual end page
          </label>
          <input
            type="number"
            required
            min={session.pages_start}
            max={session.book.total_pages}
            value={actualPage}
            onChange={e => setActualPage(e.target.value)}
            className="w-full border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <p className="text-xs text-stone-400 mt-1">
            Defaults to planned end page. Adjust if you read more or less.
          </p>
        </div>

        {error && <p className="text-sm text-red-500">{error}</p>}

        <div className="flex gap-3 pt-1">
          <button
            type="button"
            onClick={onClose}
            className="flex-1 border border-stone-200 text-stone-600 px-4 py-2 rounded-lg text-sm hover:bg-stone-100 transition-colors"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="flex-1 bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {loading ? 'Saving…' : 'Mark Complete'}
          </button>
        </div>
      </form>
    </Modal>
  )
}

'use client'

import { useRef } from 'react'

interface Props {
  value: string
  onChange: (value: string) => void
}

// Outline levels: I. → A. → 1. → a. → i.
const LEVELS = [
  { prefix: /^(I{1,3}|IV|V?I{0,3}|IX|X{0,3}|XI{0,3}|XIV|XV|XVI|XVII|XVIII|XIX|XX)\.\s/, next: 'A' },
]

type LevelKey = 'I' | 'A' | '1' | 'a' | 'i'

interface Level {
  pattern: RegExp
  nextFn: (current: string) => string
}

const OUTLINE_LEVELS: Level[] = [
  {
    // Roman numeral: I. II. III. IV. …
    pattern: /^((?:X{0,3})(?:IX|IV|V?I{0,3}))\.\s*/,
    nextFn: incrementRoman,
  },
  {
    // Capital letter: A. B. … Z.
    pattern: /^([A-Z])\.\s*/,
    nextFn: (c) => String.fromCharCode(c.charCodeAt(0) + 1) + '. ',
  },
  {
    // Arabic number: 1. 2. …
    pattern: /^(\d+)\.\s*/,
    nextFn: (c) => (parseInt(c) + 1) + '. ',
  },
  {
    // Lowercase letter: a. b. …
    pattern: /^([a-z])\.\s*/,
    nextFn: (c) => String.fromCharCode(c.charCodeAt(0) + 1) + '. ',
  },
  {
    // Lowercase roman: i. ii. iii. iv. …
    pattern: /^((?:x{0,3})(?:ix|iv|v?i{0,3}))\.\s*/,
    nextFn: incrementLowerRoman,
  },
]

function romanToInt(r: string): number {
  const vals: Record<string, number> = { i: 1, v: 5, x: 10, l: 50, c: 100, d: 500, m: 1000, I: 1, V: 5, X: 10, L: 50, C: 100, D: 500, M: 1000 }
  let total = 0
  const s = r.toLowerCase()
  for (let i = 0; i < s.length; i++) {
    const cur = vals[s[i]] ?? 0
    const next = vals[s[i + 1]] ?? 0
    total += cur < next ? -cur : cur
  }
  return total
}

function intToRoman(num: number, upper = true): string {
  const vals = [1000, 900, 500, 400, 100, 90, 50, 40, 10, 9, 5, 4, 1]
  const syms = upper
    ? ['M', 'CM', 'D', 'CD', 'C', 'XC', 'L', 'XL', 'X', 'IX', 'V', 'IV', 'I']
    : ['m', 'cm', 'd', 'cd', 'c', 'xc', 'l', 'xl', 'x', 'ix', 'v', 'iv', 'i']
  let result = ''
  for (let i = 0; i < vals.length; i++) {
    while (num >= vals[i]) { result += syms[i]; num -= vals[i] }
  }
  return result
}

function incrementRoman(current: string): string {
  return intToRoman(romanToInt(current) + 1, true) + '. '
}

function incrementLowerRoman(current: string): string {
  return intToRoman(romanToInt(current) + 1, false) + '. '
}

/**
 * Detects the indent depth (number of leading tab characters).
 */
function getIndent(line: string): number {
  let count = 0
  for (const ch of line) {
    if (ch === '\t') count++
    else break
  }
  return count
}

/**
 * Returns the prefix for the next item at the given indent level,
 * by scanning backwards through lines to find the last prefix at this level.
 */
function getNextPrefix(lines: string[], currentLineIndex: number, indent: number): string {
  const indentStr = '\t'.repeat(indent)
  const levelIdx = indent % OUTLINE_LEVELS.length

  // Scan backwards for the last line at this exact indent
  for (let i = currentLineIndex - 1; i >= 0; i--) {
    const stripped = lines[i].slice(indent) // remove indent tabs
    if (getIndent(lines[i]) === indent && stripped.length > 0) {
      const level = OUTLINE_LEVELS[levelIdx]
      const m = stripped.match(level.pattern)
      if (m) {
        return indentStr + level.nextFn(m[1])
      }
      break
    }
  }

  // First item at this level — use the first prefix
  const level = OUTLINE_LEVELS[levelIdx]
  const firstPrefixes = ['I. ', 'A. ', '1. ', 'a. ', 'i. ']
  return indentStr + firstPrefixes[levelIdx]
}

export default function OutlineEditor({ value, onChange }: Props) {
  const ref = useRef<HTMLTextAreaElement>(null)

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    const ta = ref.current
    if (!ta) return

    const start = ta.selectionStart
    const end = ta.selectionEnd
    const text = ta.value

    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()

      const before = text.slice(0, start)
      const after = text.slice(end)
      const lines = before.split('\n')
      const currentLine = lines[lines.length - 1]
      const indent = getIndent(currentLine)
      const strippedCurrent = currentLine.slice(indent)

      // Check if current line has an outline prefix
      const levelIdx = indent % OUTLINE_LEVELS.length
      const level = OUTLINE_LEVELS[levelIdx]
      const m = strippedCurrent.match(level.pattern)

      let newPrefix: string
      if (m && strippedCurrent.length > m[0].length) {
        // Current line has content — continue the list
        newPrefix = getNextPrefix(lines, lines.length, indent)
      } else if (m && strippedCurrent.length === m[0].length) {
        // Current line has prefix but no content — exit list (remove prefix)
        const newBefore = before.slice(0, before.length - currentLine.length)
        const newText = newBefore + '\n' + after
        onChange(newText)
        requestAnimationFrame(() => {
          if (!ta) return
          const pos = newBefore.length + 1
          ta.selectionStart = pos
          ta.selectionEnd = pos
        })
        return
      } else {
        // No prefix — just regular newline with same indent
        newPrefix = '\t'.repeat(indent)
      }

      const newText = before + '\n' + newPrefix + after
      onChange(newText)
      requestAnimationFrame(() => {
        if (!ta) return
        const pos = start + 1 + newPrefix.length
        ta.selectionStart = pos
        ta.selectionEnd = pos
      })
      return
    }

    if (e.key === 'Tab') {
      e.preventDefault()
      const before = text.slice(0, start)
      const after = text.slice(end)
      const lines = before.split('\n')
      const currentLine = lines[lines.length - 1]
      const indent = getIndent(currentLine)

      if (e.shiftKey) {
        // Dedent
        if (indent === 0) return
        const newIndent = indent - 1
        const strippedLine = currentLine.slice(indent)
        const levelIdx = newIndent % OUTLINE_LEVELS.length
        const level = OUTLINE_LEVELS[levelIdx]
        // Try to match and continue the list at the new level
        const newLines = [...lines]
        newLines[newLines.length - 1] = '\t'.repeat(newIndent) + strippedLine
        const newBefore = newLines.join('\n')
        const newText = newBefore + after
        onChange(newText)
        requestAnimationFrame(() => {
          if (!ta) return
          const pos = newBefore.length
          ta.selectionStart = pos
          ta.selectionEnd = pos
        })
      } else {
        // Indent — go one level deeper
        const newIndent = indent + 1
        const strippedLine = currentLine.slice(indent)
        const levelIdx = newIndent % OUTLINE_LEVELS.length

        // Find the next prefix at this deeper level by scanning previous lines
        const allLines = text.split('\n')
        const currentLineIndexInAll = before.split('\n').length - 1

        const deeperPrefix = getNextPrefix(allLines, currentLineIndexInAll, newIndent)

        // Replace just the prefix portion if it exists, or prepend
        const existing = OUTLINE_LEVELS[indent % OUTLINE_LEVELS.length]
        const mExisting = strippedLine.match(existing.pattern)
        const contentAfterPrefix = mExisting ? strippedLine.slice(mExisting[0].length) : strippedLine

        const newLine = deeperPrefix + contentAfterPrefix
        const newLines = [...lines]
        newLines[newLines.length - 1] = newLine
        const newBefore = newLines.join('\n')
        const newText = newBefore + after
        onChange(newText)
        requestAnimationFrame(() => {
          if (!ta) return
          const pos = newBefore.length
          ta.selectionStart = pos
          ta.selectionEnd = pos
        })
      }
    }
  }

  return (
    <textarea
      ref={ref}
      value={value}
      onChange={e => onChange(e.target.value)}
      onKeyDown={handleKeyDown}
      placeholder="Structure your notes here — use Enter to continue the list, Tab to indent (I. → A. → 1. → a. → i.)"
      className="w-full h-[calc(100vh-200px)] resize-none bg-stone-50 rounded-xl border border-stone-200 px-5 py-4 text-sm text-stone-700 leading-relaxed placeholder:text-stone-300 focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors font-mono"
    />
  )
}

'use client'

import { useState } from 'react'

interface Props {
  onClose: () => void
  onSuccess: () => void
}

export default function AddArticleModal({ onClose, onSuccess }: Props) {
  const [title, setTitle] = useState('')
  const [submitting, setSubmitting] = useState(false)
  const [error, setError] = useState('')

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (!title.trim()) return
    setSubmitting(true)
    setError('')

    const res = await fetch('/api/books', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title: title.trim(), type: 'article' }),
    })

    if (!res.ok) {
      const data = await res.json()
      setError(data.error ?? 'Something went wrong')
      setSubmitting(false)
      return
    }

    onSuccess()
    onClose()
  }

  return (
    <div
      className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="bg-stone-50 rounded-xl shadow-2xl w-full max-w-sm">
        <div className="flex items-center justify-between px-6 py-4 border-b border-stone-100">
          <h2 className="font-semibold text-stone-800">Add Article</h2>
          <button
            onClick={onClose}
            className="text-stone-400 hover:text-stone-600 text-xl leading-none"
          >
            ×
          </button>
        </div>

        <form onSubmit={handleSubmit} className="px-6 py-5 space-y-4">
          <div>
            <label className="block text-sm text-stone-600 mb-1.5 font-medium">Title</label>
            <input
              autoFocus
              value={title}
              onChange={e => setTitle(e.target.value)}
              placeholder="Article title…"
              className="w-full border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
            />
          </div>

          {error && <p className="text-sm text-red-500">{error}</p>}

          <div className="flex gap-3 pt-1">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 border border-stone-200 text-stone-600 px-4 py-2 rounded-lg text-sm hover:bg-stone-100 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={submitting || !title.trim()}
              className="flex-1 bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-40"
            >
              {submitting ? 'Adding…' : 'Add Article'}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import Modal from './Modal'
import type { Book } from '@/types'

interface Props {
  book: Book
  onClose: () => void
  onSuccess: () => void
}

export default function EditBookModal({ book, onClose, onSuccess }: Props) {
  const [form, setForm] = useState({
    title: book.title,
    total_pages: String(book.total_pages),
    current_page: String(book.current_page),
  })
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setLoading(true)

    const res = await fetch(`/api/books/${book.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        title: form.title.trim(),
        total_pages: Number(form.total_pages),
        current_page: Number(form.current_page),
      }),
    })

    if (!res.ok) {
      const data = await res.json()
      setError(data.error ?? 'Failed to update book')
      setLoading(false)
      return
    }

    onSuccess()
    onClose()
  }

  return (
    <Modal title="Edit Book" onClose={onClose}>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-stone-600 mb-1">Title</label>
          <input
            type="text"
            required
            autoFocus
            value={form.title}
            onChange={e => setForm(f => ({ ...f, title: e.target.value }))}
            className="w-full border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="block text-sm font-medium text-stone-600 mb-1">Total pages</label>
            <input
              type="number"
              required
              min={1}
              value={form.total_pages}
              onChange={e => setForm(f => ({ ...f, total_pages: e.target.value }))}
              className="w-full border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-stone-600 mb-1">Current page</label>
            <input
              type="number"
              min={0}
              max={Number(form.total_pages) || undefined}
              value={form.current_page}
              onChange={e => setForm(f => ({ ...f, current_page: e.target.value }))}
              className="w-full border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
        </div>

        {error && <p className="text-sm text-red-500">{error}</p>}

        <div className="flex gap-3 pt-1">
          <button
            type="button"
            onClick={onClose}
            className="flex-1 border border-stone-200 text-stone-600 px-4 py-2 rounded-lg text-sm hover:bg-stone-100 transition-colors"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="flex-1 bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {loading ? 'Saving…' : 'Save'}
          </button>
        </div>
      </form>
    </Modal>
  )
}

'use client'

import { useState } from 'react'
import Modal from './Modal'
import { supabase } from '@/lib/supabase'
import type { Session, Book } from '@/types'

interface Props {
  session: Session & { book: Book }
  onClose: () => void
  onSuccess: () => void
}

export default function EditSessionModal({ session, onClose, onSuccess }: Props) {
  const [date, setDate] = useState(session.scheduled_date)
  const [pagesEnd, setPagesEnd] = useState(String(session.pages_end))
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setLoading(true)

    const { error: err } = await supabase
      .from('sessions')
      .update({ scheduled_date: date, pages_end: Number(pagesEnd) })
      .eq('id', session.id)

    if (err) {
      setError(err.message)
      setLoading(false)
      return
    }

    onSuccess()
    onClose()
  }

  return (
    <Modal title="Edit Session" onClose={onClose}>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="bg-stone-100 rounded-lg px-4 py-3 text-sm">
          <p className="font-medium text-stone-700">{session.book.title}</p>
          <p className="text-stone-500 mt-0.5">pp. {session.pages_start}–{session.pages_end}</p>
        </div>

        <div>
          <label className="block text-sm font-medium text-stone-600 mb-1">Scheduled date</label>
          <input
            type="date"
            required
            value={date}
            onChange={e => setDate(e.target.value)}
            className="w-full border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-stone-600 mb-1">End page target</label>
          <input
            type="number"
            required
            min={session.pages_start}
            max={session.book.total_pages}
            value={pagesEnd}
            onChange={e => setPagesEnd(e.target.value)}
            className="w-full border border-stone-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>

        {error && <p className="text-sm text-red-500">{error}</p>}

        <div className="flex gap-3 pt-1">
          <button
            type="button"
            onClick={onClose}
            className="flex-1 border border-stone-200 text-stone-600 px-4 py-2 rounded-lg text-sm hover:bg-stone-100 transition-colors"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="flex-1 bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {loading ? 'Saving…' : 'Save Changes'}
          </button>
        </div>
      </form>
    </Modal>
  )
}

