'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { format, parseISO, addMonths } from 'date-fns'
import { supabase } from '@/lib/supabase'
import {
  DndContext,
  closestCenter,
  DragEndEvent,
  PointerSensor,
  useSensor,
  useSensors,
} from '@dnd-kit/core'
import {
  SortableContext,
  useSortable,
  verticalListSortingStrategy,
  arrayMove,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import AddBookModal from '@/components/AddBookModal'
import AddArticleModal from '@/components/AddArticleModal'
import EditBookModal from '@/components/EditBookModal'
import CompleteSessionModal from '@/components/CompleteSessionModal'
import EditSessionModal from '@/components/EditSessionModal'
import SessionDetailModal from '@/components/SessionDetailModal'
import WeeklyCalendar from '@/components/WeeklyCalendar'
import type { Book, Session, PriorityItem } from '@/types'

type SessionWithBook = Session & { book: Book }

// ── Sortable book row ──────────────────────────────────────────────────────────

function bookRole(sortOrder: number | null): { label: string; color: string } | null {
  if (sortOrder === 1) return { label: 'Primary', color: 'text-violet-700 bg-violet-50 border-violet-200' }
  if (sortOrder === 2) return { label: 'Secondary', color: 'text-amber-700 bg-amber-100 border-amber-300' }
  return null
}

function SortableBookRow({
  book,
  sessions,
  onComplete,
  onEdit,
}: {
  book: Book
  sessions: SessionWithBook[]
  onComplete: (book: Book) => void
  onEdit: (book: Book) => void
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: book.id,
  })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.45 : 1,
  }

  const bookSessions = sessions.filter(s => s.book_id === book.id)
  const lastSession = [...bookSessions].sort((a, b) =>
    b.scheduled_date.localeCompare(a.scheduled_date)
  )[0]
  const pct = book.total_pages > 0
    ? Math.round((book.current_page / book.total_pages) * 100)
    : 0

  const role = bookRole(book.sort_order)
  const borderClass = book.sort_order === 1
    ? 'border-violet-300'
    : book.sort_order === 2
    ? 'border-amber-300'
    : 'border-parchment-300'

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`bg-parchment-100 rounded-xl border px-4 py-3 flex items-center gap-3 transition-colors shadow-[0_2px_6px_rgba(44,26,14,0.07),0_1px_2px_rgba(44,26,14,0.05)] ${borderClass}`}
    >
      {/* Drag handle */}
      <button
        {...attributes}
        {...listeners}
        className="text-parchment-300 hover:text-parchment-500 cursor-grab active:cursor-grabbing shrink-0 touch-none"
        aria-label="Drag to reorder"
      >
        <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
          <circle cx="4" cy="3" r="1.5" />
          <circle cx="8" cy="3" r="1.5" />
          <circle cx="4" cy="8" r="1.5" />
          <circle cx="8" cy="8" r="1.5" />
          <circle cx="4" cy="13" r="1.5" />
          <circle cx="8" cy="13" r="1.5" />
        </svg>
      </button>

      {/* Role badge */}
      {role && (
        <span className={`shrink-0 text-[10px] font-bold uppercase tracking-wider border px-1.5 py-0.5 rounded ${role.color}`}>
          {role.label}
        </span>
      )}

      {/* Book info */}
      <div className="flex-1 min-w-0">
        <p className="font-medium text-parchment-900 truncate">{book.title}</p>
        <div className="flex items-center gap-2.5 mt-1.5">
          <div className="w-32 bg-parchment-300 rounded-full h-1">
            <div
              className="bg-amber-500 h-1 rounded-full transition-all"
              style={{ width: `${pct}%` }}
            />
          </div>
          <p className="text-xs text-parchment-400">
            p.&nbsp;{book.current_page}/{book.total_pages}
            {lastSession && (
              <> · ~{format(parseISO(lastSession.scheduled_date), 'MMM d')}</>
            )}
          </p>
        </div>
      </div>

      <div className="flex items-center gap-2 shrink-0">
        <button
          onClick={() => onEdit(book)}
          className="text-xs text-parchment-500 hover:text-parchment-800 border border-parchment-300 hover:border-parchment-400 px-2 py-1 rounded-lg transition-colors"
          title="Edit book"
        >
          Edit
        </button>
        <Link
          href={`/books/${book.id}`}
          className="text-xs text-parchment-500 hover:text-parchment-800 border border-parchment-300 hover:border-parchment-400 px-2 py-1 rounded-lg transition-colors"
        >
          Notes
        </Link>
        <button
          onClick={() => onComplete(book)}
          className="w-6 h-6 flex items-center justify-center rounded-full border border-parchment-300 text-parchment-400 hover:bg-forest-700 hover:border-forest-700 hover:text-white transition-colors"
          title="Mark as finished"
        >
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
            <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
          </svg>
        </button>
      </div>
    </div>
  )
}

// ── Confirm complete book modal ────────────────────────────────────────────────

function ConfirmCompleteModal({
  book,
  onClose,
  onConfirm,
}: {
  book: Book
  onClose: () => void
  onConfirm: () => void
}) {
  const [loading, setLoading] = useState(false)

  async function handleConfirm() {
    setLoading(true)
    await onConfirm()
    setLoading(false)
  }

  return (
    <div
      className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="bg-parchment-100 rounded-xl shadow-[0_8px_32px_rgba(44,26,14,0.25),0_2px_8px_rgba(44,26,14,0.15)] w-full max-w-sm border border-parchment-300">
        <div className="px-6 py-5">
          <h2 className="font-semibold text-parchment-900 mb-2">Finish &ldquo;{book.title}&rdquo;?</h2>
          <p className="text-sm text-parchment-500">
            This will mark the book as completed, promote your Secondary book to Primary,
            and move the next queued book into the Secondary slot.
          </p>
          <div className="flex gap-3 mt-5">
            <button
              onClick={onClose}
              className="flex-1 border border-parchment-300 text-parchment-700 px-4 py-2 rounded-lg text-sm hover:bg-parchment-200 transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleConfirm}
              disabled={loading}
              className="flex-1 bg-forest-700 hover:bg-forest-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
            >
              {loading ? 'Finishing…' : 'Yes, finish it'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

// ── Completed book card ────────────────────────────────────────────────────────

function CompletedBookCard({ book }: { book: Book }) {
  const [expanded, setExpanded] = useState(false)

  return (
    <div className="bg-parchment-100 rounded-xl border border-parchment-300 overflow-hidden shadow-[0_1px_4px_rgba(44,26,14,0.06)]">
      <button
        onClick={() => setExpanded(e => !e)}
        className="w-full px-4 py-3 flex items-center gap-3 text-left hover:bg-parchment-200 transition-colors"
      >
        <span className="text-parchment-400 text-xs">
          {expanded ? '▾' : '▸'}
        </span>
        <p className="flex-1 font-medium text-parchment-600 truncate">{book.title}</p>
        {book.date_finished && (
          <span className="text-xs text-parchment-400 shrink-0">
            {format(parseISO(book.date_finished), 'MMM d, yyyy')}
          </span>
        )}
        <span className="text-xs text-forest-600 font-medium shrink-0">✓ Finished</span>
      </button>

      {expanded && (
        <div className="px-4 pb-4 border-t border-parchment-200 pt-3 flex items-center justify-between gap-4">
          <div className="text-xs text-parchment-400 space-y-0.5">
            <p>{book.total_pages} pages</p>
            {book.date_finished && (
              <p>Finished {format(parseISO(book.date_finished), 'MMMM d, yyyy')}</p>
            )}
            <p>Added {format(parseISO(book.created_at), 'MMMM d, yyyy')}</p>
          </div>
          <Link
            href={`/books/${book.id}`}
            className="text-sm text-forest-600 hover:text-forest-800 font-medium shrink-0"
          >
            View Notes →
          </Link>
        </div>
      )}
    </div>
  )
}

// ── Article card ───────────────────────────────────────────────────────────────

function ArticleCard({ book, onDone }: { book: Book; onDone: (book: Book) => void }) {
  const [loading, setLoading] = useState(false)

  async function handleDone() {
    setLoading(true)
    await fetch(`/api/books/${book.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'completed' }),
    })
    onDone(book)
  }

  return (
    <div className="bg-parchment-100 rounded-xl border border-amber-200 px-4 py-3 flex items-center gap-3 shadow-[0_1px_4px_rgba(44,26,14,0.06)]">
      <div className="flex-1 min-w-0">
        <p className="font-medium text-parchment-900 truncate">{book.title}</p>
        <p className="text-xs text-amber-600 mt-0.5">Article</p>
      </div>
      <div className="flex items-center gap-2 shrink-0">
        <Link
          href={`/books/${book.id}`}
          className="text-xs text-parchment-500 hover:text-parchment-800 border border-parchment-300 hover:border-parchment-400 px-2 py-1 rounded-lg transition-colors"
        >
          Notes
        </Link>
        <button
          onClick={handleDone}
          disabled={loading}
          className="w-6 h-6 flex items-center justify-center rounded-full border border-parchment-300 text-parchment-400 hover:bg-forest-700 hover:border-forest-700 hover:text-white transition-colors disabled:opacity-40"
          title="Mark done"
        >
          {loading ? (
            <span className="text-[10px]">…</span>
          ) : (
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
              <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
            </svg>
          )}
        </button>
      </div>
    </div>
  )
}

// ── Dashboard ──────────────────────────────────────────────────────────────────

export default function Dashboard() {
  const [books, setBooks] = useState<Book[]>([])
  const [sessions, setSessions] = useState<SessionWithBook[]>([])
  const [priorities, setPriorities] = useState<PriorityItem[]>([])
  const [loading, setLoading] = useState(true)
  const [weekOffset, setWeekOffset] = useState(0)

  const [showAddBook, setShowAddBook] = useState(false)
  const [showAddArticle, setShowAddArticle] = useState(false)
  const [selectedSession, setSelectedSession] = useState<SessionWithBook | null>(null)
  const [completeTarget, setCompleteTarget] = useState<SessionWithBook | null>(null)
  const [editTarget, setEditTarget] = useState<SessionWithBook | null>(null)
  const [selectedPriority, setSelectedPriority] = useState<PriorityItem | null>(null)
  const [completeBookTarget, setCompleteBookTarget] = useState<Book | null>(null)
  const [editBookTarget, setEditBookTarget] = useState<Book | null>(null)
  const [clearing, setClearing] = useState(false)
  const [confirmClear, setConfirmClear] = useState(false)

  const refresh = useCallback(async () => {
    const today = new Date().toISOString().split('T')[0]
    const future = format(addMonths(new Date(), 3), 'yyyy-MM-dd')
    const past = format(addMonths(new Date(), -1), 'yyyy-MM-dd')

    const [booksRes, sessionsRes, prioritiesRes] = await Promise.all([
      supabase
        .from('books')
        .select('*')
        .order('sort_order', { ascending: true })
        .order('created_at', { ascending: false }),
      supabase
        .from('sessions')
        .select('*, book:books(*)')
        .gte('scheduled_date', past)
        .lte('scheduled_date', future)
        .order('scheduled_date')
        .limit(300),
      supabase
        .from('priority_items')
        .select('*')
        .gte('scheduled_date', today)
        .eq('is_completed', false)
        .order('scheduled_date'),
    ])

    setBooks((booksRes.data as Book[]) ?? [])
    setSessions((sessionsRes.data as SessionWithBook[]) ?? [])
    setPriorities((prioritiesRes.data as PriorityItem[]) ?? [])
    setLoading(false)
  }, [])

  useEffect(() => { refresh() }, [refresh])

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 8 } }))

  const activeBooks = books.filter(b => b.status === 'active' && b.type === 'book')
  const activeArticles = books.filter(b => b.status === 'active' && b.type === 'article')
  const completedBooks = books.filter(b => b.status === 'completed')

  async function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event
    if (!over || active.id === over.id) return

    const oldIndex = activeBooks.findIndex(b => b.id === active.id)
    const newIndex = activeBooks.findIndex(b => b.id === over.id)
    if (oldIndex === -1 || newIndex === -1) return

    const reordered = arrayMove(activeBooks, oldIndex, newIndex)

    setBooks(prev => {
      const others = prev.filter(b => b.status !== 'active' || b.type !== 'book')
      return [...reordered.map((b, i) => ({ ...b, sort_order: i + 1 })), ...others]
    })

    await fetch('/api/books/reorder', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ orderedIds: reordered.map(b => b.id) }),
    })

    await refresh()
  }

  async function handleCompleteBook(book: Book) {
    await fetch(`/api/books/${book.id}/complete`, { method: 'POST' })
    setCompleteBookTarget(null)
    await refresh()
  }

  async function handleCompletePriority(id: string) {
    await supabase.from('priority_items').update({ is_completed: true }).eq('id', id)
    setSelectedPriority(null)
    await refresh()
  }

  async function handleClearAll() {
    setClearing(true)
    await fetch('/api/dev/clear', { method: 'DELETE' })
    setConfirmClear(false)
    setClearing(false)
    await refresh()
  }

  async function handleDeletePriority(id: string) {
    await fetch(`/api/priority-items/${id}`, { method: 'DELETE' })
    setSelectedPriority(null)
    await refresh()
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-parchment-200 flex items-center justify-center text-parchment-400 text-sm">
        Loading…
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-parchment-200">
      {/* Header */}
      <header className="bg-parchment-900 border-b border-parchment-800 sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-6 py-4 flex items-center justify-between">
          <h1 className="text-xl font-bold font-serif text-parchment-100 tracking-tight">BookClub</h1>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setShowAddArticle(true)}
              className="text-sm text-parchment-200 hover:text-white bg-parchment-700 hover:bg-parchment-600 px-3 py-1.5 rounded-lg transition-colors font-medium"
            >
              + Article
            </button>
            <button
              onClick={() => setShowAddBook(true)}
              className="text-sm text-white bg-forest-700 hover:bg-forest-600 px-3 py-1.5 rounded-lg transition-colors font-medium"
            >
              + Book
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6 py-8 space-y-10">

        {/* ── Books ── */}
        <section>
          <div className="flex items-center justify-between mb-3">
            <h2 className="text-[11px] font-bold uppercase tracking-widest text-parchment-500">
              Books
            </h2>
            <p className="text-xs text-parchment-400">Drag to reorder · first = Primary, second = Secondary</p>
          </div>

          {activeBooks.length === 0 ? (
            <div className="text-center py-10 text-parchment-400 bg-parchment-100 rounded-xl border border-parchment-300">
              <p className="text-3xl mb-2">📚</p>
              <p className="text-sm">No books yet.</p>
              <button
                onClick={() => setShowAddBook(true)}
                className="mt-3 text-sm text-forest-600 hover:text-forest-800 hover:underline"
              >
                Add your first book →
              </button>
            </div>
          ) : (
            <DndContext
              sensors={sensors}
              collisionDetection={closestCenter}
              onDragEnd={handleDragEnd}
            >
              <SortableContext items={activeBooks.map(b => b.id)} strategy={verticalListSortingStrategy}>
                <div className="space-y-2">
                  {activeBooks.map(book => (
                    <SortableBookRow
                      key={book.id}
                      book={book}
                      sessions={sessions}
                      onComplete={() => setCompleteBookTarget(book)}
                      onEdit={() => setEditBookTarget(book)}
                    />
                  ))}
                </div>
              </SortableContext>
            </DndContext>
          )}
        </section>

        {/* ── Articles ── */}
        {activeArticles.length > 0 && (
          <section>
            <h2 className="text-[11px] font-bold uppercase tracking-widest text-parchment-500 mb-3">
              Articles
            </h2>
            <div className="space-y-2">
              {activeArticles.map(article => (
                <ArticleCard key={article.id} book={article} onDone={refresh} />
              ))}
            </div>
          </section>
        )}

        {/* ── Schedule ── */}
        <section>
          <h2 className="text-[11px] font-bold uppercase tracking-widest text-parchment-500 mb-3">
            Schedule
          </h2>

          <WeeklyCalendar
            sessions={sessions}
            priorities={priorities}
            weekOffset={weekOffset}
            onChangeWeek={setWeekOffset}
            onSelectSession={setSelectedSession}
            onSelectPriority={setSelectedPriority}
            onSessionMoved={refresh}
          />
        </section>

        {/* ── Completed ── */}
        {completedBooks.length > 0 && (
          <section>
            <h2 className="text-[11px] font-bold uppercase tracking-widest text-parchment-500 mb-3">
              Completed
            </h2>
            <div className="space-y-2">
              {completedBooks
                .sort((a, b) => (b.date_finished ?? '').localeCompare(a.date_finished ?? ''))
                .map(book => (
                  <CompletedBookCard key={book.id} book={book} />
                ))}
            </div>
          </section>
        )}
      </main>

      {/* Modals */}
      {showAddBook && (
        <AddBookModal onClose={() => setShowAddBook(false)} onSuccess={refresh} />
      )}

      {showAddArticle && (
        <AddArticleModal onClose={() => setShowAddArticle(false)} onSuccess={refresh} />
      )}

      {selectedSession && !completeTarget && !editTarget && (
        <SessionDetailModal
          session={selectedSession}
          onClose={() => setSelectedSession(null)}
          onComplete={() => setCompleteTarget(selectedSession)}
          onEdit={() => setEditTarget(selectedSession)}
        />
      )}

      {completeTarget && (
        <CompleteSessionModal
          session={completeTarget}
          onClose={() => { setCompleteTarget(null); setSelectedSession(null) }}
          onSuccess={() => { setCompleteTarget(null); setSelectedSession(null); refresh() }}
        />
      )}

      {editTarget && (
        <EditSessionModal
          session={editTarget}
          onClose={() => { setEditTarget(null); setSelectedSession(null) }}
          onSuccess={() => { setEditTarget(null); setSelectedSession(null); refresh() }}
        />
      )}

      {/* Priority item detail */}
      {selectedPriority && (
        <div
          className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
          onClick={e => { if (e.target === e.currentTarget) setSelectedPriority(null) }}
        >
          <div className="bg-parchment-100 rounded-xl shadow-[0_8px_32px_rgba(44,26,14,0.25),0_2px_8px_rgba(44,26,14,0.15)] border border-parchment-300 w-full max-w-sm">
            <div className="flex items-center justify-between px-6 py-4 border-b border-parchment-200">
              <div className="flex items-center gap-2">
                <span className="text-xs font-bold uppercase tracking-wide text-amber-700 bg-amber-50 border border-amber-200 px-1.5 py-0.5 rounded">
                  Priority
                </span>
                <h2 className="font-semibold text-parchment-900 truncate">{selectedPriority.title}</h2>
              </div>
              <button
                onClick={() => setSelectedPriority(null)}
                className="text-parchment-400 hover:text-parchment-700 text-xl leading-none ml-2"
              >
                ×
              </button>
            </div>
            <div className="px-6 py-5 space-y-4">
              {selectedPriority.description && (
                <p className="text-sm text-parchment-600">{selectedPriority.description}</p>
              )}
              <p className="text-sm text-parchment-500">
                {selectedPriority.sessions_needed} session{selectedPriority.sessions_needed !== 1 ? 's' : ''} displaced
              </p>
              <div className="grid grid-cols-2 gap-3 pt-1">
                <button
                  onClick={() => handleDeletePriority(selectedPriority.id)}
                  className="border border-parchment-300 text-parchment-700 px-4 py-2 rounded-lg text-sm hover:bg-red-50 hover:border-red-200 hover:text-red-600 transition-colors"
                >
                  Delete
                </button>
                <button
                  onClick={() => handleCompletePriority(selectedPriority.id)}
                  className="bg-amber-500 hover:bg-amber-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
                >
                  ✓ Done
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {completeBookTarget && (
        <ConfirmCompleteModal
          book={completeBookTarget}
          onClose={() => setCompleteBookTarget(null)}
          onConfirm={() => handleCompleteBook(completeBookTarget)}
        />
      )}

      {editBookTarget && (
        <EditBookModal
          book={editBookTarget}
          onClose={() => setEditBookTarget(null)}
          onSuccess={() => { setEditBookTarget(null); refresh() }}
        />
      )}

      {/* Dev footer */}
      <footer className="max-w-4xl mx-auto px-6 py-6 flex justify-end">
        {confirmClear ? (
          <div className="flex items-center gap-3">
            <span className="text-xs text-parchment-400">Wipe all books, sessions & articles?</span>
            <button
              onClick={() => setConfirmClear(false)}
              className="text-xs text-parchment-400 hover:text-parchment-700"
            >
              Cancel
            </button>
            <button
              onClick={handleClearAll}
              disabled={clearing}
              className="text-xs text-white bg-red-500 hover:bg-red-600 px-3 py-1.5 rounded-lg transition-colors disabled:opacity-50"
            >
              {clearing ? 'Clearing…' : 'Yes, clear everything'}
            </button>
          </div>
        ) : (
          <button
            onClick={() => setConfirmClear(true)}
            className="text-xs text-parchment-300 hover:text-red-400 transition-colors"
          >
            Clear all data
          </button>
        )}
      </footer>
    </div>
  )
}

toolUseResult.content:
'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { format, parseISO, addMonths } from 'date-fns'
import { supabase } from '@/lib/supabase'
import {
  DndContext,
  closestCenter,
  DragEndEvent,
  PointerSensor,
  useSensor,
  useSensors,
} from '@dnd-kit/core'
import {
  SortableContext,
  useSortable,
  verticalListSortingStrategy,
  arrayMove,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import AddBookModal from '@/components/AddBookModal'
import AddArticleModal from '@/components/AddArticleModal'
import EditBookModal from '@/components/EditBookModal'
import CompleteSessionModal from '@/components/CompleteSessionModal'
import EditSessionModal from '@/components/EditSessionModal'
import SessionDetailModal from '@/components/SessionDetailModal'
import WeeklyCalendar from '@/components/WeeklyCalendar'
import type { Book, Session, PriorityItem } from '@/types'

type SessionWithBook = Session & { book: Book }

// ── Sortable book row ──────────────────────────────────────────────────────────

function bookRole(sortOrder: number | null): { label: string; color: string } | null {
  if (sortOrder === 1) return { label: 'Primary', color: 'text-violet-700 bg-violet-50 border-violet-200' }
  if (sortOrder === 2) return { label: 'Secondary', color: 'text-amber-700 bg-amber-100 border-amber-300' }
  return null
}

function SortableBookRow({
  book,
  sessions,
  onComplete,
  onEdit,
}: {
  book: Book
  sessions: SessionWithBook[]
  onComplete: (book: Book) => void
  onEdit: (book: Book) => void
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: book.id,
  })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.45 : 1,
  }

  const bookSessions = sessions.filter(s => s.book_id === book.id)
  const lastSession = [...bookSessions].sort((a, b) =>
    b.scheduled_date.localeCompare(a.scheduled_date)
  )[0]
  const pct = book.total_pages > 0
    ? Math.round((book.current_page / book.total_pages) * 100)
    : 0

  const role = bookRole(book.sort_order)
  const borderClass = book.sort_order === 1
    ? 'border-violet-300'
    : book.sort_order === 2
    ? 'border-amber-300'
    : 'border-parchment-300'

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`bg-parchment-100 rounded-xl border px-4 py-3 flex items-center gap-3 transition-colors shadow-[0_2px_6px_rgba(44,26,14,0.07),0_1px_2px_rgba(44,26,14,0.05)] ${borderClass}`}
    >
      {/* Drag handle */}
      <button
        {...attributes}
        {...listeners}
        className="text-parchment-300 hover:text-parchment-500 cursor-grab active:cursor-grabbing shrink-0 touch-none"
        aria-label="Drag to reorder"
      >
        <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
          <circle cx="4" cy="3" r="1.5" />
          <circle cx="8" cy="3" r="1.5" />
          <circle cx="4" cy="8" r="1.5" />
          <circle cx="8" cy="8" r="1.5" />
          <circle cx="4" cy="13" r="1.5" />
          <circle cx="8" cy="13" r="1.5" />
        </svg>
      </button>

      {/* Role badge */}
      {role && (
        <span className={`shrink-0 text-[10px] font-bold uppercase tracking-wider border px-1.5 py-0.5 rounded ${role.color}`}>
          {role.label}
        </span>
      )}

      {/* Book info */}
      <div className="flex-1 min-w-0">
        <p className="font-medium text-parchment-900 truncate">{book.title}</p>
        <div className="flex items-center gap-2.5 mt-1.5">
          <div className="w-32 bg-parchment-300 rounded-full h-1">
            <div
              className="bg-amber-500 h-1 rounded-full transition-all"
              style={{ width: `${pct}%` }}
            />
          </div>
          <p className="text-xs text-parchment-400">
            p.&nbsp;{book.current_page}/{book.total_pages}
            {lastSession && (
              <> · ~{format(parseISO(lastSession.scheduled_date), 'MMM d')}</>
            )}
          </p>
        </div>
      </div>

      <div className="flex items-center gap-2 shrink-0">
        <button
          onClick={() => onEdit(book)}
          className="text-xs text-parchment-500 hover:text-parchment-800 border border-parchment-300 hover:border-parchment-400 px-2 py-1 rounded-lg transition-colors"
          title="Edit book"
        >
          Edit
        </button>
        <Link
          href={`/books/${book.id}`}
          className="text-xs text-parchment-500 hover:text-parchment-800 border border-parchment-300 hover:border-parchment-400 px-2 py-1 rounded-lg transition-colors"
        >
          Notes
        </Link>
        <button
          onClick={() => onComplete(book)}
          className="w-6 h-6 flex items-center justify-center rounded-full border border-parchment-300 text-parchment-400 hover:bg-forest-700 hover:border-forest-700 hover:text-white transition-colors"
          title="Mark as finished"
        >
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
            <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
          </svg>
        </button>
      </div>
    </div>
  )
}

// ── Confirm complete book modal ────────────────────────────────────────────────

function ConfirmCompleteModal({
  book,
  onClose,
  onConfirm,
}: {
  book: Book
  onClose: () => void
  onConfirm: () => void
}) {
  const [loading, setLoading] = useState(false)

  async function handleConfirm() {
    setLoading(true)
    await onConfirm()
    setLoading(false)
  }

  return (
    <div
      className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="bg-parchment-100 rounded-xl shadow-[0_8px_32px_rgba(44,26,14,0.25),0_2px_8px_rgba(44,26,14,0.15)] w-full max-w-sm border border-parchment-300">
        <div className="px-6 py-5">
          <h2 className="font-semibold text-parchment-900 mb-2">Finish &ldquo;{book.title}&rdquo;?</h2>
          <p className="text-sm text-parchment-500">
            This will mark the book as completed, promote your Secondary book to Primary,
            and move the next queued book into the Secondary slot.
          </p>
          <div className="flex gap-3 mt-5">
            <button
              onClick={onClose}
              className="flex-1 border border-parchment-300 text-parchment-700 px-4 py-2 rounded-lg text-sm hover:bg-parchment-200 transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleConfirm}
              disabled={loading}
              className="flex-1 bg-forest-700 hover:bg-forest-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
            >
              {loading ? 'Finishing…' : 'Yes, finish it'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

// ── Completed book card ────────────────────────────────────────────────────────

function CompletedBookCard({ book }: { book: Book }) {
  const [expanded, setExpanded] = useState(false)

  return (
    <div className="bg-parchment-100 rounded-xl border border-parchment-300 overflow-hidden shadow-[0_1px_4px_rgba(44,26,14,0.06)]">
      <button
        onClick={() => setExpanded(e => !e)}
        className="w-full px-4 py-3 flex items-center gap-3 text-left hover:bg-parchment-200 transition-colors"
      >
        <span className="text-parchment-400 text-xs">
          {expanded ? '▾' : '▸'}
        </span>
        <p className="flex-1 font-medium text-parchment-600 truncate">{book.title}</p>
        {book.date_finished && (
          <span className="text-xs text-parchment-400 shrink-0">
            {format(parseISO(book.date_finished), 'MMM d, yyyy')}
          </span>
        )}
        <span className="text-xs text-forest-600 font-medium shrink-0">✓ Finished</span>
      </button>

      {expanded && (
        <div className="px-4 pb-4 border-t border-parchment-200 pt-3 flex items-center justify-between gap-4">
          <div className="text-xs text-parchment-400 space-y-0.5">
            <p>{book.total_pages} pages</p>
            {book.date_finished && (
              <p>Finished {format(parseISO(book.date_finished), 'MMMM d, yyyy')}</p>
            )}
            <p>Added {format(parseISO(book.created_at), 'MMMM d, yyyy')}</p>
          </div>
          <Link
            href={`/books/${book.id}`}
            className="text-sm text-forest-600 hover:text-forest-800 font-medium shrink-0"
          >
            View Notes →
          </Link>
        </div>
      )}
    </div>
  )
}

// ── Article card ───────────────────────────────────────────────────────────────

function ArticleCard({ book, onDone }: { book: Book; onDone: (book: Book) => void }) {
  const [loading, setLoading] = useState(false)

  async function handleDone() {
    setLoading(true)
    await fetch(`/api/books/${book.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'completed' }),
    })
    onDone(book)
  }

  return (
    <div className="bg-parchment-100 rounded-xl border border-amber-200 px-4 py-3 flex items-center gap-3 shadow-[0_1px_4px_rgba(44,26,14,0.06)]">
      <div className="flex-1 min-w-0">
        <p className="font-medium text-parchment-900 truncate">{book.title}</p>
        <p className="text-xs text-amber-600 mt-0.5">Article</p>
      </div>
      <div className="flex items-center gap-2 shrink-0">
        <Link
          href={`/books/${book.id}`}
          className="text-xs text-parchment-500 hover:text-parchment-800 border border-parchment-300 hover:border-parchment-400 px-2 py-1 rounded-lg transition-colors"
        >
          Notes
        </Link>
        <button
          onClick={handleDone}
          disabled={loading}
          className="w-6 h-6 flex items-center justify-center rounded-full border border-parchment-300 text-parchment-400 hover:bg-forest-700 hover:border-forest-700 hover:text-white transition-colors disabled:opacity-40"
          title="Mark done"
        >
          {loading ? (
            <span className="text-[10px]">…</span>
          ) : (
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
              <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
            </svg>
          )}
        </button>
      </div>
    </div>
  )
}

// ── Dashboard ──────────────────────────────────────────────────────────────────

export default function Dashboard() {
  const [books, setBooks] = useState<Book[]>([])
  const [sessions, setSessions] = useState<SessionWithBook[]>([])
  const [priorities, setPriorities] = useState<PriorityItem[]>([])
  const [loading, setLoading] = useState(true)
  const [weekOffset, setWeekOffset] = useState(0)

  const [showAddBook, setShowAddBook] = useState(false)
  const [showAddArticle, setShowAddArticle] = useState(false)
  const [selectedSession, setSelectedSession] = useState<SessionWithBook | null>(null)
  const [completeTarget, setCompleteTarget] = useState<SessionWithBook | null>(null)
  const [editTarget, setEditTarget] = useState<SessionWithBook | null>(null)
  const [selectedPriority, setSelectedPriority] = useState<PriorityItem | null>(null)
  const [completeBookTarget, setCompleteBookTarget] = useState<Book | null>(null)
  const [editBookTarget, setEditBookTarget] = useState<Book | null>(null)
  const [clearing, setClearing] = useState(false)
  const [confirmClear, setConfirmClear] = useState(false)

  const refresh = useCallback(async () => {
    const today = new Date().toISOString().split('T')[0]
    const future = format(addMonths(new Date(), 3), 'yyyy-MM-dd')
    const past = format(addMonths(new Date(), -1), 'yyyy-MM-dd')

    const [booksRes, sessionsRes, prioritiesRes] = await Promise.all([
      supabase
        .from('books')
        .select('*')
        .order('sort_order', { ascending: true })
        .order('created_at', { ascending: false }),
      supabase
        .from('sessions')
        .select('*, book:books(*)')
        .gte('scheduled_date', past)
        .lte('scheduled_date', future)
        .order('scheduled_date')
        .limit(300),
      supabase
        .from('priority_items')
        .select('*')
        .gte('scheduled_date', today)
        .eq('is_completed', false)
        .order('scheduled_date'),
    ])

    setBooks((booksRes.data as Book[]) ?? [])
    setSessions((sessionsRes.data as SessionWithBook[]) ?? [])
    setPriorities((prioritiesRes.data as PriorityItem[]) ?? [])
    setLoading(false)
  }, [])

  useEffect(() => { refresh() }, [refresh])

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 8 } }))

  const activeBooks = books.filter(b => b.status === 'active' && b.type === 'book')
  const activeArticles = books.filter(b => b.status === 'active' && b.type === 'article')
  const completedBooks = books.filter(b => b.status === 'completed')

  async function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event
    if (!over || active.id === over.id) return

    const oldIndex = activeBooks.findIndex(b => b.id === active.id)
    const newIndex = activeBooks.findIndex(b => b.id === over.id)
    if (oldIndex === -1 || newIndex === -1) return

    const reordered = arrayMove(activeBooks, oldIndex, newIndex)

    setBooks(prev => {
      const others = prev.filter(b => b.status !== 'active' || b.type !== 'book')
      return [...reordered.map((b, i) => ({ ...b, sort_order: i + 1 })), ...others]
    })

    await fetch('/api/books/reorder', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ orderedIds: reordered.map(b => b.id) }),
    })

    await refresh()
  }

  async function handleCompleteBook(book: Book) {
    await fetch(`/api/books/${book.id}/complete`, { method: 'POST' })
    setCompleteBookTarget(null)
    await refresh()
  }

  async function handleCompletePriority(id: string) {
    await supabase.from('priority_items').update({ is_completed: true }).eq('id', id)
    setSelectedPriority(null)
    await refresh()
  }

  async function handleClearAll() {
    setClearing(true)
    await fetch('/api/dev/clear', { method: 'DELETE' })
    setConfirmClear(false)
    setClearing(false)
    await refresh()
  }

  async function handleDeletePriority(id: string) {
    await fetch(`/api/priority-items/${id}`, { method: 'DELETE' })
    setSelectedPriority(null)
    await refresh()
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-parchment-200 flex items-center justify-center text-parchment-400 text-sm">
        Loading…
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-parchment-200">
      {/* Header */}
      <header className="bg-parchment-900 border-b border-parchment-800 sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-6 py-4 flex items-center justify-between">
          <h1 className="text-xl font-bold font-serif text-parchment-100 tracking-tight">BookClub</h1>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setShowAddArticle(true)}
              className="text-sm text-parchment-200 hover:text-white bg-parchment-700 hover:bg-parchment-600 px-3 py-1.5 rounded-lg transition-colors font-medium"
            >
              + Article
            </button>
            <button
              onClick={() => setShowAddBook(true)}
              className="text-sm text-white bg-forest-700 hover:bg-forest-600 px-3 py-1.5 rounded-lg transition-colors font-medium"
            >
              + Book
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6 py-8 space-y-10">

        {/* ── Books ── */}
        <section>
          <div className="flex items-center justify-between mb-3">
            <h2 className="text-[11px] font-bold uppercase tracking-widest text-parchment-500">
              Books
            </h2>
            <p className="text-xs text-parchment-400">Drag to reorder · first = Primary, second = Secondary</p>
          </div>

          {activeBooks.length === 0 ? (
            <div className="text-center py-10 text-parchment-400 bg-parchment-100 rounded-xl border border-parchment-300">
              <p className="text-3xl mb-2">📚</p>
              <p className="text-sm">No books yet.</p>
              <button
                onClick={() => setShowAddBook(true)}
                className="mt-3 text-sm text-forest-600 hover:text-forest-800 hover:underline"
              >
                Add your first book →
              </button>
            </div>
          ) : (
            <DndContext
              sensors={sensors}
              collisionDetection={closestCenter}
              onDragEnd={handleDragEnd}
            >
              <SortableContext items={activeBooks.map(b => b.id)} strategy={verticalListSortingStrategy}>
                <div className="space-y-2">
                  {activeBooks.map(book => (
                    <SortableBookRow
                      key={book.id}
                      book={book}
                      sessions={sessions}
                      onComplete={() => setCompleteBookTarget(book)}
                      onEdit={() => setEditBookTarget(book)}
                    />
                  ))}
                </div>
              </SortableContext>
            </DndContext>
          )}
        </section>

        {/* ── Articles ── */}
        {activeArticles.length > 0 && (
          <section>
            <h2 className="text-[11px] font-bold uppercase tracking-widest text-parchment-500 mb-3">
              Articles
            </h2>
            <div className="space-y-2">
              {activeArticles.map(article => (
                <ArticleCard key={article.id} book={article} onDone={refresh} />
              ))}
            </div>
          </section>
        )}

        {/* ── Schedule ── */}
        <section>
          <h2 className="text-[11px] font-bold uppercase tracking-widest text-parchment-500 mb-3">
            Schedule
          </h2>

          <WeeklyCalendar
            sessions={sessions}
            priorities={priorities}
            weekOffset={weekOffset}
            onChangeWeek={setWeekOffset}
            onSelectSession={setSelectedSession}
            onSelectPriority={setSelectedPriority}
            onSessionMoved={refresh}
          />
        </section>

        {/* ── Completed ── */}
        {completedBooks.length > 0 && (
          <section>
            <h2 className="text-[11px] font-bold uppercase tracking-widest text-parchment-500 mb-3">
              Completed
            </h2>
            <div className="space-y-2">
              {completedBooks
                .sort((a, b) => (b.date_finished ?? '').localeCompare(a.date_finished ?? ''))
                .map(book => (
                  <CompletedBookCard key={book.id} book={book} />
                ))}
            </div>
          </section>
        )}
      </main>

      {/* Modals */}
      {showAddBook && (
        <AddBookModal onClose={() => setShowAddBook(false)} onSuccess={refresh} />
      )}

      {showAddArticle && (
        <AddArticleModal onClose={() => setShowAddArticle(false)} onSuccess={refresh} />
      )}

      {selectedSession && !completeTarget && !editTarget && (
        <SessionDetailModal
          session={selectedSession}
          onClose={() => setSelectedSession(null)}
          onComplete={() => setCompleteTarget(selectedSession)}
          onEdit={() => setEditTarget(selectedSession)}
        />
      )}

      {completeTarget && (
        <CompleteSessionModal
          session={completeTarget}
          onClose={() => { setCompleteTarget(null); setSelectedSession(null) }}
          onSuccess={() => { setCompleteTarget(null); setSelectedSession(null); refresh() }}
        />
      )}

      {editTarget && (
        <EditSessionModal
          session={editTarget}
          onClose={() => { setEditTarget(null); setSelectedSession(null) }}
          onSuccess={() => { setEditTarget(null); setSelectedSession(null); refresh() }}
        />
      )}

      {/* Priority item detail */}
      {selectedPriority && (
        <div
          className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
          onClick={e => { if (e.target === e.currentTarget) setSelectedPriority(null) }}
        >
          <div className="bg-parchment-100 rounded-xl shadow-[0_8px_32px_rgba(44,26,14,0.25),0_2px_8px_rgba(44,26,14,0.15)] border border-parchment-300 w-full max-w-sm">
            <div className="flex items-center justify-between px-6 py-4 border-b border-parchment-200">
              <div className="flex items-center gap-2">
                <span className="text-xs font-bold uppercase tracking-wide text-amber-700 bg-amber-50 border border-amber-200 px-1.5 py-0.5 rounded">
                  Priority
                </span>
                <h2 className="font-semibold text-parchment-900 truncate">{selectedPriority.title}</h2>
              </div>
              <button
                onClick={() => setSelectedPriority(null)}
                className="text-parchment-400 hover:text-parchment-700 text-xl leading-none ml-2"
              >
                ×
              </button>
            </div>
            <div className="px-6 py-5 space-y-4">
              {selectedPriority.description && (
                <p className="text-sm text-parchment-600">{selectedPriority.description}</p>
              )}
              <p className="text-sm text-parchment-500">
                {selectedPriority.sessions_needed} session{selectedPriority.sessions_needed !== 1 ? 's' : ''} displaced
              </p>
              <div className="grid grid-cols-2 gap-3 pt-1">
                <button
                  onClick={() => handleDeletePriority(selectedPriority.id)}
                  className="border border-parchment-300 text-parchment-700 px-4 py-2 rounded-lg text-sm hover:bg-red-50 hover:border-red-200 hover:text-red-600 transition-colors"
                >
                  Delete
                </button>
                <button
                  onClick={() => handleCompletePriority(selectedPriority.id)}
                  className="bg-amber-500 hover:bg-amber-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
                >
                  ✓ Done
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {completeBookTarget && (
        <ConfirmCompleteModal
          book={completeBookTarget}
          onClose={() => setCompleteBookTarget(null)}
          onConfirm={() => handleCompleteBook(completeBookTarget)}
        />
      )}

      {editBookTarget && (
        <EditBookModal
          book={editBookTarget}
          onClose={() => setEditBookTarget(null)}
          onSuccess={() => { setEditBookTarget(null); refresh() }}
        />
      )}

      {/* Dev footer */}
      <footer className="max-w-4xl mx-auto px-6 py-6 flex justify-end">
        {confirmClear ? (
          <div className="flex items-center gap-3">
            <span className="text-xs text-parchment-400">Wipe all books, sessions & articles?</span>
            <button
              onClick={() => setConfirmClear(false)}
              className="text-xs text-parchment-400 hover:text-parchment-700"
            >
              Cancel
            </button>
            <button
              onClick={handleClearAll}
              disabled={clearing}
              className="text-xs text-white bg-red-500 hover:bg-red-600 px-3 py-1.5 rounded-lg transition-colors disabled:opacity-50"
            >
              {clearing ? 'Clearing…' : 'Yes, clear everything'}
            </button>
          </div>
        ) : (
          <button
            onClick={() => setConfirmClear(true)}
            className="text-xs text-parchment-300 hover:text-red-400 transition-colors"
          >
            Clear all data
          </button>
        )}
      </footer>
    </div>
  )
}

