'use client'

import { useState } from 'react'
import Modal from './Modal'
import type { Book } from '@/types'

interface Props {
  book: Book
  onClose: () => void
  onSuccess: () => void
}

export default function EditBookModal({ book, onClose, onSuccess }: Props) {
  const [form, setForm] = useState({
    title: book.title,
    total_pages: String(book.total_pages),
    current_page: String(book.current_page),
  })
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setLoading(true)

    const res = await fetch(`/api/books/${book.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        title: form.title.trim(),
        total_pages: Number(form.total_pages),
        current_page: Number(form.current_page),
      }),
    })

    if (!res.ok) {
      const data = await res.json()
      setError(data.error ?? 'Failed to update book')
      setLoading(false)
      return
    }

    onSuccess()
    onClose()
  }

  return (
    <Modal title="Edit Book" onClose={onClose}>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-parchment-700 mb-1">Title</label>
          <input
            type="text"
            required
            autoFocus
            value={form.title}
            onChange={e => setForm(f => ({ ...f, title: e.target.value }))}
            className="w-full border border-parchment-300 bg-parchment-50 rounded-lg px-3 py-2 text-sm text-parchment-900 focus:outline-none focus:ring-2 focus:ring-forest-700/20 focus:border-forest-600 transition-colors"
          />
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="block text-sm font-medium text-parchment-700 mb-1">Total pages</label>
            <input
              type="number"
              required
              min={1}
              value={form.total_pages}
              onChange={e => setForm(f => ({ ...f, total_pages: e.target.value }))}
              className="w-full border border-parchment-300 bg-parchment-50 rounded-lg px-3 py-2 text-sm text-parchment-900 focus:outline-none focus:ring-2 focus:ring-forest-700/20 focus:border-forest-600 transition-colors"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-parchment-700 mb-1">Current page</label>
            <input
              type="number"
              min={0}
              max={Number(form.total_pages) || undefined}
              value={form.current_page}
              onChange={e => setForm(f => ({ ...f, current_page: e.target.value }))}
              className="w-full border border-parchment-300 bg-parchment-50 rounded-lg px-3 py-2 text-sm text-parchment-900 focus:outline-none focus:ring-2 focus:ring-forest-700/20 focus:border-forest-600 transition-colors"
            />
          </div>
        </div>

        {error && <p className="text-sm text-red-500">{error}</p>}

        <div className="flex gap-3 pt-1">
          <button
            type="button"
            onClick={onClose}
            className="flex-1 border border-parchment-300 text-parchment-700 px-4 py-2 rounded-lg text-sm hover:bg-parchment-200 transition-colors"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="flex-1 bg-forest-700 hover:bg-forest-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {loading ? 'Saving…' : 'Save'}
          </button>
        </div>
      </form>
    </Modal>
  )
}

