'use client'

import { useState } from 'react'
import Modal from './Modal'
import type { Session, Book } from '@/types'

interface Props {
  session: Session & { book: Book }
  onClose: () => void
  onSuccess: () => void
}

export default function CompleteSessionModal({ session, onClose, onSuccess }: Props) {
  const [actualPage, setActualPage] = useState(String(session.pages_end))
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setLoading(true)

    const res = await fetch(`/api/sessions/${session.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'complete',
        actual_end_page: Number(actualPage),
      }),
    })

    if (!res.ok) {
      const data = await res.json()
      setError(data.error ?? 'Failed to complete session')
      setLoading(false)
      return
    }

    onSuccess()
    onClose()
  }

  return (
    <Modal title="Complete Session" onClose={onClose}>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="bg-forest-50 rounded-lg border border-forest-100 px-4 py-3 text-sm">
          <p className="font-medium text-forest-900">{session.book.title}</p>
          <p className="text-forest-700 mt-0.5">
            Planned: pp. {session.pages_start}–{session.pages_end}
          </p>
        </div>

        <div>
          <label className="block text-sm font-medium text-parchment-700 mb-1">
            Actual end page
          </label>
          <input
            type="number"
            required
            min={session.pages_start}
            max={session.book.total_pages}
            value={actualPage}
            onChange={e => setActualPage(e.target.value)}
            className="w-full border border-parchment-300 bg-parchment-50 rounded-lg px-3 py-2 text-sm text-parchment-900 focus:outline-none focus:ring-2 focus:ring-forest-700/20 focus:border-forest-600 transition-colors"
          />
          <p className="text-xs text-parchment-400 mt-1">
            Defaults to planned end page. Adjust if you read more or less.
          </p>
        </div>

        {error && <p className="text-sm text-red-500">{error}</p>}

        <div className="flex gap-3 pt-1">
          <button
            type="button"
            onClick={onClose}
            className="flex-1 border border-parchment-300 text-parchment-700 px-4 py-2 rounded-lg text-sm hover:bg-parchment-200 transition-colors"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="flex-1 bg-forest-700 hover:bg-forest-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {loading ? 'Saving…' : 'Mark Complete'}
          </button>
        </div>
      </form>
    </Modal>
  )
}

