// ── Droppable day column ────────────────────────────────────────────────────

function DroppableDay({
  date,
  children,
  isCurrentDay,
}: {
  date: string
  children: React.ReactNode
  isCurrentDay: boolean
}) {
  const { setNodeRef, isOver } = useDroppable({ id: date })
  return (
    <div
      ref={setNodeRef}
      className={`p-1.5 space-y-1.5 min-h-28 flex-1 transition-colors rounded-b-md ${
        isOver ? 'bg-forest-50/80 ring-1 ring-inset ring-forest-300' : ''
      }`}
    >
      {children}
    </div>
  )
}

// ── Main calendar ───────────────────────────────────────────────────────────

export default function WeeklyCalendar({
  sessions,
  priorities,
  weekOffset,
  onChangeWeek,
  onSelectSession,
  onSelectPriority,
  onSessionMoved,
}: Props) {
  const [activeSession, setActiveSession] = useState<SessionWithBook | null>(null)
  const [optimisticMoves, setOptimisticMoves] = useState<Record<string, string>>({})

  const todayStart = startOfDay(new Date())
  const weekStart = addWeeks(startOfWeek(new Date(), { weekStartsOn: 1 }), weekOffset)
  const days = Array.from({ length: 7 }, (_, i) => addDays(weekStart, i))
  const weekLabel = `${format(days[0], 'MMM d')} – ${format(days[6], 'MMM d, yyyy')}`

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 6 } }))

  const displaySessions = sessions.map(s =>
    optimisticMoves[s.id] ? { ...s, scheduled_date: optimisticMoves[s.id] } : s
  )

  function handleDragStart(event: DragStartEvent) {
    const s = sessions.find(s => s.id === event.active.id)
    setActiveSession(s ?? null)
  }

  async function handleDragEnd(event: DragEndEvent) {
    setActiveSession(null)
    const { active, over } = event
    if (!over) return

    const sessionId = active.id as string
    const newDate = over.id as string
    const session = sessions.find(s => s.id === sessionId)
    if (!session || session.scheduled_date === newDate) return

    setOptimisticMoves(prev => ({ ...prev, [sessionId]: newDate }))

    await fetch(`/api/sessions/${sessionId}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ scheduled_date: newDate }),
    })

    setOptimisticMoves(prev => {
      const next = { ...prev }
      delete next[sessionId]
      return next
    })
    onSessionMoved()
  }

  return (
    <DndContext
      sensors={sensors}
      onDragStart={handleDragStart}
      onDragEnd={handleDragEnd}
    >
      {/* Week navigation */}
      <div className="flex items-center justify-between mb-4">
        <button
          onClick={() => onChangeWeek(weekOffset - 1)}
          className="text-sm text-parchment-500 hover:text-parchment-900 px-3 py-1.5 rounded-lg hover:bg-parchment-300/50 transition-colors"
        >
          ← Prev
        </button>
        <span className="text-sm font-medium text-parchment-700">{weekLabel}</span>
        <button
          onClick={() => onChangeWeek(weekOffset + 1)}
          className="text-sm text-parchment-500 hover:text-parchment-900 px-3 py-1.5 rounded-lg hover:bg-parchment-300/50 transition-colors"
        >
          Next →
        </button>
      </div>

      {/* Calendar grid */}
      <div className="overflow-x-auto">
        <div className="grid grid-cols-7 min-w-[560px] rounded-xl border border-parchment-300 overflow-hidden bg-parchment-50 shadow-[0_2px_8px_rgba(44,26,14,0.07)]">
          {days.map((day, i) => {
            const iso = format(day, 'yyyy-MM-dd')
            const isCurrentDay = isToday(day)
            const isPast = isBefore(day, todayStart)
            const daySessions = displaySessions.filter(s => s.scheduled_date === iso)
            const dayItems = priorities.filter(p => p.scheduled_date === iso)

            const completedSessions = daySessions.filter(s => s.is_completed)
            const upcomingSessions = daySessions.filter(s => !s.is_completed)

            return (
              <div
                key={iso}
                className={`flex flex-col relative ${i < 6 ? 'border-r border-parchment-200' : ''} ${
                  isCurrentDay ? 'bg-forest-50/30' : ''
                }`}
              >
                {/* Day header */}
                <div className={`px-2.5 pt-3 pb-2 border-b border-parchment-200 ${
                  isCurrentDay ? 'bg-forest-100/50' : 'bg-parchment-100/60'
                }`}>
                  <p className={`text-[11px] font-bold tracking-wider uppercase ${
                    isCurrentDay ? 'text-forest-600' : isPast ? 'text-parchment-400' : 'text-parchment-500'
                  }`}>
                    {DAYS[i]}
                  </p>
                  <p className={`text-2xl font-semibold leading-tight mt-0.5 ${
                    isCurrentDay ? 'text-forest-700' : isPast ? 'text-parchment-300' : 'text-parchment-700'
                  }`}>
                    {format(day, 'd')}
                  </p>
                </div>

                <DroppableDay date={iso} isCurrentDay={isCurrentDay}>
                  {/* Completed sessions */}
                  {completedSessions.map(session => (
                    <button
                      key={session.id}
                      onClick={() => onSelectSession(session)}
                      className="w-full text-left rounded-md border-l-[3px] border-parchment-300 bg-parchment-200 px-2 py-1.5 text-xs shadow-sm transition-all opacity-60"
                    >
                      <p className="font-semibold truncate leading-tight text-parchment-400 line-through">
                        {session.book.title}
                      </p>
                      <p className="mt-0.5 text-parchment-300 flex items-center gap-1">
                        <span>✓</span>
                        <span>pp.&nbsp;{session.pages_start}–{session.actual_end_page ?? session.pages_end}</span>
                      </p>
                    </button>
                  ))}

                  {/* Upcoming sessions — draggable */}
                  {upcomingSessions.map(session => (
                    <DraggableSession
                      key={session.id}
                      session={session}
                      onClick={() => onSelectSession(session)}
                    />
                  ))}

                  {/* Priority items */}
                  {dayItems.map(item => (
                    <button
                      key={item.id}
                      onClick={() => onSelectPriority(item)}
                      className="w-full text-left rounded-md border-l-[3px] border-amber-400 bg-parchment-50 hover:bg-amber-50 px-2 py-1.5 text-xs shadow-sm hover:shadow transition-all group"
                    >
                      <p className="font-semibold text-parchment-800 truncate group-hover:text-amber-800 transition-colors leading-tight">
                        {item.title}
                      </p>
                      <p className="text-amber-600 mt-0.5">Priority item</p>
                    </button>
                  ))}
                </DroppableDay>
              </div>
            )
          })}
        </div>
      </div>

      <DragOverlay>
        {activeSession && <SessionOverlay session={activeSession} />}
      </DragOverlay>
    </DndContext>
  )
}

